  1→interface BookmarkInput {
  2→  url: string;
  3→  title: string | null;
  4→  selection: string | null;
  5→  tags: string[] | null;
  6→  sensitivity: string;
  7→}
  8→
  9→interface CaptureMessage {
 10→  action: "captureBookmark";
 11→  input: BookmarkInput;
 12→}
 13→
 14→interface CaptureResult {
 15→  success: boolean;
 16→  error?: string;
 17→  data?: {
 18→    id: string;
 19→    status: string;
 20→    title: string;
 21→    tags: string[];
 22→  };
 23→}
 24→
 25→interface GraphQLResponse {
 26→  data?: {
 27→    captureBookmark: {
 28→      id: string;
 29→      status: string;
 30→      title: string;
 31→      tags: string[];
 32→    };
 33→  };
 34→  errors?: Array<{ message: string }>;
 35→}
 36→
 37→const CAPTURE_MUTATION = `
 38→  mutation CaptureBookmark($input: BookmarkInput!) {
 39→    captureBookmark(input: $input) {
 40→      id
 41→      status
 42→      title
 43→      tags
 44→    }
 45→  }
 46→`;
 47→
 48→chrome.runtime.onMessage.addListener(
 49→  (
 50→    message: CaptureMessage,
 51→    _sender: chrome.runtime.MessageSender,
 52→    sendResponse: (response: CaptureResult) => void,
 53→  ) => {
 54→    if (message.action === "captureBookmark") {
 55→      handleCapture(message.input).then(sendResponse);
 56→      return true; // keep message channel open for async response
 57→    }
 58→  },
 59→);
 60→
 61→async function handleCapture(input: BookmarkInput): Promise<CaptureResult> {
 62→  try {
 63→    const { apiUrl, jwtToken } = await chrome.storage.local.get([
 64→      "apiUrl",
 65→      "jwtToken",
 66→    ]);
 67→
 68→    if (!apiUrl || !jwtToken) {
 69→      return { success: false, error: "Extension not configured" };
 70→    }
 71→
 72→    const graphqlUrl = (apiUrl as string).replace(/\/+$/, "") + "/graphql";
 73→
 74→    const res = await fetch(graphqlUrl, {
 75→      method: "POST",
 76→      headers: {
 77→        "Content-Type": "application/json",
 78→        Authorization: "Bearer " + jwtToken,
 79→      },
 80→      body: JSON.stringify({
 81→        query: CAPTURE_MUTATION,
 82→        variables: { input },
 83→      }),
 84→    });
 85→
 86→    if (!res.ok) {
 87→      const text = await res.text();
 88→      return { success: false, error: `HTTP ${res.status}: ${text}` };
 89→    }
 90→
 91→    const json: GraphQLResponse = await res.json();
 92→
 93→    if (json.errors && json.errors.length > 0) {
 94→      return { success: false, error: json.errors[0].message };
 95→    }
 96→
 97→    return { success: true, data: json.data!.captureBookmark };
 98→  } catch (err) {
 99→    return { success: false, error: (err as Error).message };
100→  }
101→}
