 99→// Do sends a GraphQL request and decodes the response data into result.
100→func (c *Client) Do(ctx context.Context, query string, variables map[string]any, result any) error {
101→	body, err := json.Marshal(graphqlRequest{
102→		Query:     query,
103→		Variables: variables,
104→	})
105→	if err != nil {
106→		return fmt.Errorf("cli: marshal request: %w", err)
107→	}
108→
109→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, c.apiURL+"/graphql", bytes.NewReader(body))
110→	if err != nil {
111→		return fmt.Errorf("cli: create request: %w", err)
112→	}
113→	req.Header.Set("Content-Type", "application/json")
114→	if c.token != "" {
115→		req.Header.Set("Authorization", "Bearer "+c.token)
116→	}
117→
118→	resp, err := c.httpClient.Do(req)
119→	if err != nil {
120→		return fmt.Errorf("cli: send request: %w", err)
121→	}
122→	defer func() { _ = resp.Body.Close() }()
123→
124→	respBody, err := io.ReadAll(resp.Body)
125→	if err != nil {
126→		return fmt.Errorf("cli: read response: %w", err)
127→	}
128→
129→	if resp.StatusCode == http.StatusUnauthorized {
130→		return fmt.Errorf("cli: not authenticated (run 'flotsam login' first)")
131→	}
132→	if resp.StatusCode != http.StatusOK {
133→		return fmt.Errorf("cli: unexpected status %d: %s", resp.StatusCode, string(respBody))
134→	}
135→
136→	var gqlResp graphqlResponse
137→	if err := json.Unmarshal(respBody, &gqlResp); err != nil {
138→		return fmt.Errorf("cli: parse response: %w", err)
139→	}
140→
141→	if len(gqlResp.Errors) > 0 {
142→		messages := make([]string, len(gqlResp.Errors))
143→		for i, e := range gqlResp.Errors {
144→			messages[i] = e.Message
145→		}
146→		return fmt.Errorf("cli: %s", strings.Join(messages, "; "))
147→	}
148→
149→	if result != nil {
150→		if err := json.Unmarshal(gqlResp.Data, result); err != nil {
151→			return fmt.Errorf("cli: decode data: %w", err)
152→		}
153→	}
154→
155→	return nil
156→}
