  1→package cli
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"os"
  7→	"path/filepath"
  8→)
  9→
 10→// Config holds CLI client configuration.
 11→type Config struct {
 12→	APIURL string `json:"api_url"`
 13→	Token  string `json:"token"`
 14→}
 15→
 16→const (
 17→	configDirName  = "flotsam"
 18→	configFileName = "config.json"
 19→	defaultAPIURL  = "http://localhost:8081"
 20→)
 21→
 22→// ConfigDir returns the configuration directory path, respecting XDG_CONFIG_HOME.
 23→// Creates the directory with 0700 permissions if it does not exist.
 24→func ConfigDir() (string, error) {
 25→	base := os.Getenv("XDG_CONFIG_HOME")
 26→	if base == "" {
 27→		home, err := os.UserHomeDir()
 28→		if err != nil {
 29→			return "", fmt.Errorf("cli: home directory: %w", err)
 30→		}
 31→		base = filepath.Join(home, ".config")
 32→	}
 33→	dir := filepath.Join(base, configDirName)
 34→	if err := os.MkdirAll(dir, 0700); err != nil {
 35→		return "", fmt.Errorf("cli: create config dir: %w", err)
 36→	}
 37→	return dir, nil
 38→}
 39→
 40→// configPath returns the full path to the config file.
 41→func configPath() (string, error) {
 42→	dir, err := ConfigDir()
 43→	if err != nil {
 44→		return "", err
 45→	}
 46→	return filepath.Join(dir, configFileName), nil
 47→}
 48→
 49→// LoadConfig reads configuration from disk and applies environment variable overrides.
 50→// Returns defaults if the config file does not exist.
 51→func LoadConfig() (*Config, error) {
 52→	cfg := &Config{
 53→		APIURL: defaultAPIURL,
 54→	}
 55→
 56→	path, err := configPath()
 57→	if err != nil {
 58→		return nil, err
 59→	}
 60→
 61→	data, err := os.ReadFile(path)
 62→	if err != nil {
 63→		if os.IsNotExist(err) {
 64→			applyEnvOverrides(cfg)
 65→			return cfg, nil
 66→		}
 67→		return nil, fmt.Errorf("cli: read config: %w", err)
 68→	}
 69→
 70→	if err := json.Unmarshal(data, cfg); err != nil {
 71→		return nil, fmt.Errorf("cli: parse config: %w", err)
 72→	}
 73→
 74→	applyEnvOverrides(cfg)
 75→	return cfg, nil
 76→}
 77→
 78→// SaveConfig writes configuration to disk with restrictive permissions.
 79→func SaveConfig(cfg *Config) error {
 80→	path, err := configPath()
 81→	if err != nil {
 82→		return err
 83→	}
 84→
 85→	data, err := json.MarshalIndent(cfg, "", "  ")
 86→	if err != nil {
 87→		return fmt.Errorf("cli: marshal config: %w", err)
 88→	}
 89→
 90→	if err := os.WriteFile(path, data, 0600); err != nil {
 91→		return fmt.Errorf("cli: write config: %w", err)
 92→	}
 93→	return nil
 94→}
 95→
 96→// SetURL updates the API URL in the config file.
 97→func SetURL(url string) error {
 98→	cfg, err := LoadConfig()
 99→	if err != nil {
100→		return err
101→	}
102→	cfg.APIURL = url
103→	return SaveConfig(cfg)
104→}
105→
106→// SetToken updates the auth token in the config file.
107→func SetToken(token string) error {
108→	cfg, err := LoadConfig()
109→	if err != nil {
110→		return err
111→	}
112→	cfg.Token = token
113→	return SaveConfig(cfg)
114→}
115→
116→// applyEnvOverrides applies environment variable overrides to the config.
117→func applyEnvOverrides(cfg *Config) {
118→	if v := os.Getenv("FLOTSAM_API_URL"); v != "" {
119→		cfg.APIURL = v
120→	}
121→	if v := os.Getenv("FLOTSAM_TOKEN"); v != "" {
122→		cfg.Token = v
123→	}
124→}
